const submit = async () => {
  if (!file) {
    return alert("Silakan pilih file foto KTP Anda terlebih dahulu.");
  }

  setLoading(true);

  const form = new FormData();
  form.append("ktp", file);

  try {
    await API.post("/verify", form, {
      headers: { 'Content-Type': 'multipart/form-data' }
    });

    // Force user to become verified in localStorage
    const storedUser = localStorage.getItem("user");

    if (storedUser) {
      const user = JSON.parse(storedUser);

      user.isVerified = "confirmed";

      localStorage.setItem(
        "user",
        JSON.stringify(user)
      );
    }

    alert("KTP berhasil diverifikasi!");

    setPreview(null);
    setFile(null);

    // Refresh app so verification status updates everywhere
    window.location.reload();

  } catch (err) {
    console.error(err);
    alert("Gagal mengunggah file. Silakan coba beberapa saat lagi.");
  } finally {
    setLoading(false);
  }
};
